import{_ as t,o as r,c as o,aq as a}from"./chunks/framework.DH0nG2Fl.js";const u=JSON.parse('{"title":"Extension Development","description":"","frontmatter":{"prev":{"text":"Development Guides","link":"/development/"},"next":{"text":"Your First Extension","link":"/development/extensions/start"}},"headers":[],"relativePath":"development/extensions/index.md","filePath":"development/extensions/index.md","lastUpdated":1782486320000}'),i={name:"development/extensions/index.md"};function n(s,e,l,d,p,c){return r(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="extension-development" tabindex="-1">Extension Development <a class="header-anchor" href="#extension-development" aria-label="Permalink to “Extension Development”">​</a></h1><p>So you want to build an extension for Paperback - great, you&#39;re in the right place. This guide will walk you through:</p><ul><li>Setting up an extension from scratch.</li><li>Understanding what an extension needs to do, and what it is allowed to do.</li><li>Using the right tools and debugging effectively.</li><li>Organizing your extension&#39;s codebase.</li><li>A deep dive into advanced features.</li></ul><h2 id="before-you-begin" tabindex="-1">Before you begin <a class="header-anchor" href="#before-you-begin" aria-label="Permalink to “Before you begin”">​</a></h2><h3 id="about-paperback-0-9" tabindex="-1">About Paperback 0.9 <a class="header-anchor" href="#about-paperback-0-9" aria-label="Permalink to “About Paperback 0.9”">​</a></h3><p>Throughout this guide, we will be building an extension for <strong>Paperback 0.9</strong> step by step. Note that 0.9 is not yet available to everyone, but you can find out how to join the beta on the <a href="https://discord.com/channels/965890377896845352/1361230107632599192" target="_blank" rel="noreferrer">Inkdex Discord Server FAQ</a>.</p><h3 id="typescript-prerequisite" tabindex="-1">TypeScript prerequisite <a class="header-anchor" href="#typescript-prerequisite" aria-label="Permalink to “TypeScript prerequisite”">​</a></h3><p>All code in this guide is written in <strong>TypeScript</strong>, using <strong>npm</strong> as a package manager. If you are not yet comfortable with TypeScript, the following resources are a good starting point:</p><ul><li><a href="https://www.typescriptlang.org/docs/handbook/intro.html" target="_blank" rel="noreferrer">The TypeScript Handbook</a> — the official reference, covering the language from the ground up.</li><li><a href="https://javascript.info/" target="_blank" rel="noreferrer">JavaScript.info</a> — if you are new to JavaScript entirely, start here. Make sure you are comfortable with <code>async</code>/<code>await</code> and Promises before moving on, as they are used extensively throughout.</li></ul><h3 id="web-interaction-prerequisite" tabindex="-1">Web interaction prerequisite <a class="header-anchor" href="#web-interaction-prerequisite" aria-label="Permalink to “Web interaction prerequisite”">​</a></h3><p>Extensions retrieve data from websites using either a <strong>REST API</strong> or <strong>HTML scraping</strong> (via Cheerio). Paperback provides custom helpers to handle CloudFlare protections for you, so you do not need to deal with that directly, but you do need to understand the underlying concepts:</p><ul><li><a href="https://www.restapitutorial.com/" target="_blank" rel="noreferrer">RestAPITutorial.com</a> — a practical introduction to REST APIs.</li><li><a href="https://cheerio.js.org/docs/intro/" target="_blank" rel="noreferrer">Cheerio.js.org</a> — documentation for the HTML parsing library used in extensions.</li></ul><blockquote><p><strong>Note:</strong> This guide does not cover how to reverse-engineer a website (i.e. figuring out which endpoints return what data, or how to intercept requests). That knowledge is a prerequisite. If you need to build it up, <a href="https://pptr.dev/guides/what-is-puppeteer" target="_blank" rel="noreferrer">pptr.dev</a> and browser DevTools are good places to start.</p></blockquote>',13)])])}const g=t(i,[["render",n]]);export{u as __pageData,g as default};
